/**
 * Differential tests for materialized-membership semi/anti-joins (MINUS, EXISTS, NOT EXISTS whose right side is a
 * single statement pattern correlated on one variable): results must be identical across the per-row probe path
 * (membership disabled), the LongHashSet membership set, and the generic evaluator. The miss threshold is forced to 0
 * so the materialized path engages even on tiny datasets.
 */
public class LmdbNativeMembershipJoinTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String MEMBERSHIP_IMPL = "rdf4j.lmdb.membership.impl";
	private static final String MEMBERSHIP_THRESHOLD = "rdf4j.lmdb.membership.missThreshold";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		System.setProperty(MEMBERSHIP_THRESHOLD, "0");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI type = vf.createIRI(EX, "type");
			IRI item = vf.createIRI(EX, "Item");
			IRI sold = vf.createIRI(EX, "sold");
			IRI offerFor = vf.createIRI(EX, "offerFor");
			IRI inGraph = vf.createIRI(EX, "g1");
			for (int i = 0; i < 40; i++) {
				IRI subject = vf.createIRI(EX, "item" + i);
				conn.add(subject, type, item);
				if (i % 3 == 0) {
					conn.add(subject, sold, vf.createLiteral("2024-01-0" + (1 + i % 9)));
				}
				if (i % 5 == 0) {
					conn.add(vf.createIRI(EX, "offer" + i), offerFor, subject);
				}
			}
			// a named-graph-only membership fact: context handling must stay correct
			conn.add(vf.createIRI(EX, "item1"), sold, vf.createLiteral("2024-02-01"), inGraph);
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
		System.clearProperty(MEMBERSHIP_IMPL);
		System.clearProperty(MEMBERSHIP_THRESHOLD);
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream()
					.map(LmdbNativeMembershipJoinTest::canonical)
					.sorted()
					.collect(Collectors.toList());
		}
	}

	private static String canonical(BindingSet bindings) {
		return bindings.getBindingNames()
				.stream()
				.sorted()
				.filter(name -> bindings.getValue(name) != null)
				.map(name -> name + "=" + bindings.getValue(name))
				.collect(Collectors.joining(";", "[", "]"));
	}

	private void assertAllModesAgree(String query) {
		String previousImpl = System.getProperty(MEMBERSHIP_IMPL);
		String previousNative = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, "false");
			List<String> generic = rows(query);
			System.setProperty(NATIVE_FLAG, "true");
			System.setProperty(MEMBERSHIP_IMPL, "off");
			assertThat(rows(query)).as("probe path vs generic for:\n" + query).isEqualTo(generic);
			System.setProperty(MEMBERSHIP_IMPL, "hash");
			assertThat(rows(query)).as("hash membership vs generic for:\n" + query).isEqualTo(generic);
		} finally {
			restore(MEMBERSHIP_IMPL, previousImpl);
			restore(NATIVE_FLAG, previousNative);
		}
	}

	private static void restore(String key, String value) {
		if (value == null) {
			System.clearProperty(key);
		} else {
			System.setProperty(key, value);
		}
	}

	private static String q(String body) {
		return "PREFIX ex: <" + EX + ">\n" + body;
	}

	@ParameterizedTest
	@ValueSource(strings = {
			// MINUS on subject position
			"SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:type ex:Item MINUS { ?s ex:sold ?d } }",
			// NOT EXISTS on object position
			"SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:type ex:Item . FILTER NOT EXISTS { ?o ex:offerFor ?s } }",
			// EXISTS on subject position
			"SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:type ex:Item . FILTER EXISTS { ?s ex:sold ?d } }",
			// combined, mirroring REAL_ESTATE q7
			"SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:type ex:Item . "
					+ "FILTER NOT EXISTS { ?o ex:offerFor ?s } MINUS { ?s ex:sold ?d } }",
			// non-aggregate row-stream root with MINUS
			"SELECT ?s WHERE { ?s ex:type ex:Item MINUS { ?s ex:sold ?d } }",
			// DISTINCT + NOT EXISTS, mirroring REAL_ESTATE q3
			"SELECT DISTINCT ?s WHERE { ?s ex:type ex:Item . FILTER NOT EXISTS { ?s ex:sold ?d } }" })
	void membershipModesAgree(String body) {
		assertAllModesAgree(q(body));
	}
}
